#include<bits/stdc++.h>
using namespace std;
int n,a[1000010],s[1000010];
long long jc[1000010],ans=1;
const int mod=998244353;
int lowbit(int x)
{
    return x&-x;
}
void add(int x,int v)
{
    for(int i=x;i<=1000000;i+=lowbit(i))
    {
        s[i]+=v;
    }
}
int query(int x)
{
    int ans=0;
    for(int i=x;i>=1;i-=lowbit(i))
    {
        ans+=s[i];
    }
    return ans;
}
int main()
{
    jc[0]=1;
    for(int i=1;i<=1000000;i++)
    {
        jc[i]=jc[i-1]*i%mod;
    }
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        int x;
        scanf("%d",&x);
        int tmp=x-1-query(x);
        ans+=1ll*jc[n-i]*tmp%mod;
        ans%=mod;
        add(x,1);
    }
    printf("%lld",ans);
    return 0;
}
